local function getEquippedWeapon()
	local char = LP.Character
	if char then
		for _, item in ipairs(char:GetChildren()) do
			if item:IsA("Tool") then return item.Name end
		end
	end
	for _, item in ipairs(LP.Backpack:GetChildren()) do
		if item:IsA("Tool") then return item.Name end
	end
	return "Pistol"
end

local function getZombieId(zombie)
	return tonumber(zombie.Name:match("%d+"))
end

local function getZombiePosition(zombie)
	local root = zombie:FindFirstChild("HumanoidRootPart") or zombie.PrimaryPart
	return root and root.Position or Vector3.new(0, 0, 0)
end

local function damageZombie(id, amount)
	if ZombieDamageRemote then
		pcall(function() ZombieDamageRemote:FireServer(id, amount) end)
	end
end

local function hitZombieWithGun(zombie, id)
	if GunHitRemote then
		pcall(function() GunHitRemote:FireServer(getEquippedWeapon(), id, getZombiePosition(zombie)) end)
	end
end

local function getSortedZombies()
	local folder = workspace:FindFirstChild("Zombies_Local")
	if not folder then return {} end
	local list = {}
	for _, zombie in ipairs(folder:GetChildren()) do
		if zombie:IsA("Model") then
			local id = getZombieId(zombie)
			if id then table.insert(list, { model = zombie, id = id }) end
		end
	end
	return list
end

local ESP_COLORS = {
	Red    = Color3.fromRGB(255, 50,  50),
	Orange = Color3.fromRGB(255, 140,  0),
	Yellow = Color3.fromRGB(255, 220,  0),
	Purple = Color3.fromRGB(180,   0, 255),
}

local function clearESP()
	for _, h in pairs(espTable) do pcall(function() h:Destroy() end) end
	espTable = {}
end

local function applyESPColor(color)
	for _, h in pairs(espTable) do h.FillColor = color end
end

local function updateESP()
	if not Toggles.ZombieESP.Value then return end
	local folder = workspace:FindFirstChild("Zombies_Local")
	if not folder then clearESP() return end
	for zombie, h in pairs(espTable) do
		if not zombie.Parent then
			pcall(function() h:Destroy() end)
			espTable[zombie] = nil
		end
	end
	local fillColor = ESP_COLORS[Options.ESPColor.Value] or ESP_COLORS.Red
	for _, zombie in ipairs(folder:GetChildren()) do
		if zombie:IsA("Model") and not espTable[zombie] then
			local h = Instance.new("Highlight")
			h.FillColor           = fillColor
			h.OutlineColor        = Color3.fromRGB(255, 255, 255)
			h.FillTransparency    = 0.45
			h.OutlineTransparency = 0
			h.Adornee             = zombie
			h.Parent              = zombie
			espTable[zombie]      = h
		end
	end
end

local function setCharacterTransparency(transparency)
	local character = LP.Character
	if not character then return end
	for _, part in pairs(character:GetDescendants()) do
		if part:IsA("BasePart") and part.Name ~= "HumanoidRootPart" then
			part.Transparency = transparency
		end
	end
end

local function startSeatReturnHeartbeat()
	if seatReturnHeartbeatConnection then
		seatReturnHeartbeatConnection:Disconnect()
		seatReturnHeartbeatConnection = nil
	end
	seatReturnHeartbeatConnection = RunService.Heartbeat:Connect(function()
		if not invis_on or not currentSeat or not currentSeat.Parent then return end
		local character = LP.Character
		if not character then return end
		local hrp = character:FindFirstChild("HumanoidRootPart")
		if not hrp then return end
		currentSeat.CFrame = CFrame.new(hrp.Position + Vector3.new(0, 9, 0))
	end)
end

local function stopSeatReturnHeartbeat()
	if seatReturnHeartbeatConnection then
		seatReturnHeartbeatConnection:Disconnect()
		seatReturnHeartbeatConnection = nil
	end
end

local function disableInvisibility()
	if not invis_on then return end
	invis_on = false
	setCharacterTransparency(0)
	task.spawn(function()
		local inv = workspace:FindFirstChild("invischair")
		if inv then pcall(function() inv:Destroy() end) end
	end)
	stopSeatReturnHeartbeat()
	currentSeat = nil
	currentSeatPosition = nil
end

local function enableInvisibility()
	if invis_on then return end
	invis_on = true
	setCharacterTransparency(invis_transparency)
	local character = LP.Character
	if not character then invis_on = false return end
	local humanoidRootPart = character:FindFirstChild("HumanoidRootPart")
	local humanoid = character:FindFirstChildOfClass("Humanoid")
	if not humanoidRootPart or not humanoid then
		invis_on = false
		setCharacterTransparency(0)
		return
	end
	local savedpos = humanoidRootPart.CFrame
	humanoid:ChangeState(Enum.HumanoidStateType.Jumping)
	task.wait(0.15)
	local abovePos = humanoidRootPart.Position + Vector3.new(0, 9, 0)
	task.wait(0.05)
	pcall(function() character:MoveTo(abovePos) end)
	task.wait(0.05)
	if not character:FindFirstChild("HumanoidRootPart") or character.HumanoidRootPart.Position.Y < voidLevelYThreshold then
		pcall(function() character:MoveTo(savedpos.Position) end)
		invis_on = false
		setCharacterTransparency(0)
		pcall(function() Toggles.InvisEnabled:SetValue(false) end)
		return
	end
	local Seat = Instance.new("Seat")
	Seat.Parent = workspace
	Seat.Anchored = false
	Seat.CanCollide = false
	Seat.Name = "invischair"
	Seat.Transparency = 1
	Seat.Position = abovePos
	currentSeat = Seat
	local torso = character:FindFirstChild("Torso") or character:FindFirstChild("UpperTorso")
	if torso then
		local Weld = Instance.new("Weld")
		Weld.Part0 = torso
		Weld.Part1 = Seat
		Weld.C0 = CFrame.new(0, 9, 0)
		Weld.Parent = Seat
		task.wait()
		pcall(function() humanoidRootPart.CFrame = savedpos end)
		currentSeatPosition = Seat.Position
		startSeatReturnHeartbeat()
	else
		Seat:Destroy()
		currentSeat = nil
		currentSeatPosition = nil
		invis_on = false
		setCharacterTransparency(0)
		pcall(function() Toggles.InvisEnabled:SetValue(false) end)
		stopSeatReturnHeartbeat()
	end
end

local function setInvisTransparency(value)
	invis_transparency = math.clamp(value, 0, 1)
	if invis_on then setCharacterTransparency(invis_transparency) end
end

local function startFly()
	local pchar = LP.Character
	if not pchar then return end
	local root = pchar:FindFirstChild("HumanoidRootPart") or pchar.PrimaryPart
	if not root then return end
	flyFloating     = true
	flyBaseHeight   = root.Position.Y
	flyBodyVelocity = Instance.new("BodyVelocity")
	flyBodyVelocity.MaxForce = Vector3.new(0, math.huge, 0)
	flyBodyVelocity.Velocity = Vector3.new(0, 0, 0)
	flyBodyVelocity.Parent   = root
	flyLoop = RunService.Heartbeat:Connect(function()
		local c = LP.Character
		if not c then return end
		local r = c:FindFirstChild("HumanoidRootPart") or c.PrimaryPart
		if r and flyBodyVelocity and flyFloating then
			local diff = (flyBaseHeight + Options.FlyHeight.Value) - r.Position.Y
			flyBodyVelocity.Velocity = Vector3.new(0, diff * 8, 0)
		end
	end)
end

local function stopFly()
	flyFloating = false
	if flyLoop then flyLoop:Disconnect() flyLoop = nil end
	if flyBodyVelocity then
		pcall(function() flyBodyVelocity:Destroy() end)
		flyBodyVelocity = nil
	end
end

local function getZombieCount()
	local folder = workspace:FindFirstChild("Zombies_Local")
	return folder and #folder:GetChildren() or 0
end

local function getEstCredits()
	local kills = killsStat and killsStat.Value or 0
	return kills * CREDITS_PER_KILL * currentMultiplier
end

local function startAutoKill()
	autoKillLoop = task.spawn(function()
		while Toggles.AutoKill.Value do
			for _, data in ipairs(getSortedZombies()) do
				if not Toggles.AutoKill.Value then break end
				hitZombieWithGun(data.model, data.id)
			end
			task.wait(Options.AutoKillDelay.Value)
		end
	end)
end

local function stopAutoKill()
	if autoKillLoop then task.cancel(autoKillLoop) autoKillLoop = nil end
end

local function startInstaKill()
	instaKillLoop = task.spawn(function()
		while Toggles.InstaKill.Value do
			for _, data in ipairs(getSortedZombies()) do
				if not Toggles.InstaKill.Value then break end
				damageZombie(data.id, Options.InstaKillDamage.Value)
			end
			task.wait(Options.InstaKillDelay.Value)
		end
	end)
end

local function stopInstaKill()
	if instaKillLoop then task.cancel(instaKillLoop) instaKillLoop = nil end
end

local function killAll()
	for _, data in ipairs(getSortedZombies()) do
		damageZombie(data.id, 999999999)
	end
end

local function startSkip()
	skipLoop = task.spawn(function()
		while Toggles.AutoSkipWave.Value do
			if SkipVoteRemote then pcall(function() SkipVoteRemote:FireServer(true) end) end
			task.wait(1)
		end
	end)
end

local function stopSkip()
	if skipLoop then task.cancel(skipLoop) skipLoop = nil end
end

local function instantSkip()
	if invis_on then
		disableInvisibility()
		pcall(function() Toggles.InvisEnabled:SetValue(false) end)
		task.wait(0.15)
	end
	local pchar = LP.Character
	if not pchar then return end
	local root = pchar:FindFirstChild("HumanoidRootPart") or pchar.PrimaryPart
	if not root then return end
	root.CFrame = CFrame.new(
		-346.646454, 429.63501, -351.827087,
		0.731384635, 0, 0.681965172,
		0, 1, 0,
		-0.681965172, 0, 0.731384635
	)
end

